import{_ as e,o as r,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G02: 董事高階經理人異動審計 - 績效管理專家 (hr-performance-reviewer) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8064_東捷/20260429/G02_董事高階經理人異動審計.md","filePath":"審計報告庫/經營審計/8064_東捷/20260429/G02_董事高階經理人異動審計.md"}'),l={name:"審計報告庫/經營審計/8064_東捷/20260429/G02_董事高階經理人異動審計.md"};function o(n,a,h,s,c,d){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="g02-董事高階經理人異動審計-績效管理專家-hr-performance-reviewer-審計報告" tabindex="-1">G02: 董事高階經理人異動審計 - 績效管理專家 (hr-performance-reviewer) 審計報告 <a class="header-anchor" href="#g02-董事高階經理人異動審計-績效管理專家-hr-performance-reviewer-審計報告" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計 - 績效管理專家 (hr-performance-reviewer) 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>核心經營團隊穩定，但獨董 3 年內 4 人離職/解任，2026/3 歸零致委員會停擺。志聖工業入股觸發當然解任，暴露治理漏洞。風險：高。時效：2026/4。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>獨董異動率 133%</strong>：3 年內 4 人次離職/解任，2026/3 歸零。審計委員會停擺 62 天。</li><li><strong>核心經理人穩定</strong>：董事長嚴瑞雄、總經理陳贊仁、財務主管王姿惠均無異動。2025 EPS 1.36 元。</li><li><strong>診斷</strong>：獨董異動觸及治理紅線，委員會停擺致內控真空，構成結構性風險。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="近三年董事會異動全景" tabindex="-1">近三年董事會異動全景 <a class="header-anchor" href="#近三年董事會異動全景" aria-label="Permalink to &quot;近三年董事會異動全景&quot;">​</a></h3><p>核心成員為嚴瑞雄（董事長）、陳贊仁（總經理）及 3 名獨董。異動集中於獨董：喻銘鐸 2025/2 辭任、2025/6 補選曹正鵠、林宜靜 2026/2 辭任、曹正鵠與梁又文 2026/3 因志聖工業持股 &gt;5% 當然解任。至 2026/3/27 獨董全數離場，審計委員會癱瘓。4 人次異動遠超正常範疇，部分獨董提前離場顯示對外部投資者布局早有知悉，非「正常汰換」而是「治理架構讓位」。</p><h3 id="高階經理人與新任執行長" tabindex="-1">高階經理人與新任執行長 <a class="header-anchor" href="#高階經理人與新任執行長" aria-label="Permalink to &quot;高階經理人與新任執行長&quot;">​</a></h3><p>總經理陳贊仁 2023-2025 未異動。2026/4/15 新設「執行長」，由嚴璐（嚴瑞雄姪女）擔任，為家族第三代接班部署。嚴璐同時為東台精機副總、志聖工業董事。執行長新設意味經營權重新分配，嚴璐交叉兼任暗示東捷納入集團聯盟，決策獨立性存疑，為「家族資本重組」訊號。</p><h3 id="稽核主管與財務主管" tabindex="-1">稽核主管與財務主管 <a class="header-anchor" href="#稽核主管與財務主管" aria-label="Permalink to &quot;稽核主管與財務主管&quot;">​</a></h3><p>財務主管王姿惠 2023-2025 無異動。稽核主管資料因合併報告格式未能取得完整資訊。財務主管穩定為正面訊號，但在審計委員會癱瘓下若稽核主管同步異動，將構成「內控雙失靈」紅燈。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><h3 id="警訊一-審計委員會停擺與內控真空" tabindex="-1">警訊一：審計委員會停擺與內控真空 <a class="header-anchor" href="#警訊一-審計委員會停擺與內控真空" aria-label="Permalink to &quot;警訊一：審計委員會停擺與內控真空&quot;">​</a></h3><p>2026/3/27 至 2026/5/28（約 62 天），審計委員會與薪資報酬委員會因全數委員解任而無法運作。財務報告監督機制形同虛設，若此期間發生重大關聯交易或財務異常，外部股東缺乏制衡管道。這是治理失靈的經典定義——沒有人能監督做事的人。風險等級：極高。</p><h3 id="警訊二-志聖工業入股的治理脆弱性" tabindex="-1">警訊二：志聖工業入股的治理脆弱性 <a class="header-anchor" href="#警訊二-志聖工業入股的治理脆弱性" aria-label="Permalink to &quot;警訊二：志聖工業入股的治理脆弱性&quot;">​</a></h3><p>志聖工業以 10.176 億元取得 10.82% 持股，觸發獨董當然解任。此交易風險在於：(1) 控股結構從家族轉向外部策略投資者；(2) 嚴璐兼具投資方代表與經營方執行長角色，形成利益衝突疑慮；(3) 5/28 改選後獨董若仍不足法定人數，東捷面臨下市或降級風險。此為結構性不確定因素，投資者應追蹤改選結果作為關鍵依據。</p><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: N/A（本題為治理審計，無需財務採集器）</li><li><strong>yfinance</strong>: N/A</li><li><strong>年報/法說</strong>: OK — 年報路徑 <code>/Users/kaipro/.openclaw/workspace/work/年報資料庫/8064/</code>（2023-2025 合併財務報告，含董事長嚴瑞雄、總經理陳贊仁、財務主管王姿惠之簽章資訊；主要股東三新公司持股 7.71%）</li><li><strong>MOPS 重訊（經 web_search 交叉驗證）</strong>: <ul><li>2026/4/14 獨立董事施俊旭辭任（個人健康及職涯規劃）</li><li>2026/3/27 獨立董事曹正鵠、梁又文當然解任（志聖工業取得 &gt;5% 持股）</li><li>2026/2/23 獨立董事林宜靜辭任（個人規劃，3/31 生效）</li><li>2025/6/5 補選曹正鵠為獨立董事</li><li>2025/5/14 董事及獨立董事全面改選</li></ul></li><li><strong>關鍵核對碼</strong>: <ul><li>「志聖工業斥資 10.176 億元認購 20,000 張，每股 50.88 元，2026/3/27 起持股 10.82%」</li><li>「嚴璐：臺大財金系、西北大學整合行銷碩士、2011 年加入東台精機、2026/4/15 新任執行長」</li><li>「2025 年 EPS 1.36 元、營收 28.7 億、稅後淨利 2.25 億」</li></ul></li></ul>',22)])])}const u=e(l,[["render",o]]);export{p as __pageData,u as default};
